\begin{tikzpicture}[scale=0.85]
\draw[->] (0,0)--(0,7.4);
\draw[->] (0,0)--(5.5,0);
\foreach \v/\p in {0/0,1000/1,2000/2,3000/3,4000/4,5000/5,6000/6} {\draw (-0.2,\p)--(0,\p); \node[left,font=\scriptsize] at (-0.2,\p) {$\v$};}
