\node[below,font=\scriptsize] at (1.1,0) {Ashby};
\node[below,font=\tiny] at (2.5,0) {Belford};
\node[below,font=\scriptsize] at (3.9,0) {Corby};
\node[rotate=90,font=\small] at (-1.9,3) {Population};
